class Solution {
public:
    int addMinimum(string word) {
        int count = 0;
        char last = 'a';
        for (char c : word) {
            if (last == 'a' && c != 'b') {
                count += 1;
            } else if (last == 'b' && c != 'c') {
                count += 1;
            } else if (last == 'c' && c != 'a') {
                count += 2;
            }
            last = c;
        }
        if (last == 'a') {
            count += 2;
        } else if (last == 'b') {
            count += 1;
        }
        return count;
    }
};

